   216	int fcb_put_len(const struct fcb *fcbp, uint8_t *buf, uint16_t len)
   217	{
   218		if (len < 0x80) {
   219			buf[0] = len ^ ~fcbp->f_erase_value;
   220			return 1;
   221		} else if (len <= FCB_MAX_LEN) {
   222			buf[0] = (len | 0x80) ^ ~fcbp->f_erase_value;
   223			buf[1] = (len >> 7) ^ ~fcbp->f_erase_value;
   224			return 2;
   225		} else {
   226			return -EINVAL;
   227		}
