   278	int fcb_sector_hdr_read(struct fcb *fcbp, struct flash_sector *sector, struct fcb_disk_area *fdap)
   279	{
   280		struct fcb_disk_area fda;
   281		int rc;
   282	
   283		if (!fdap) {
   284			fdap = &fda;
   285		}
   286		rc = fcb_flash_read(fcbp, sector, 0, fdap, sizeof(*fdap));
   287		if (rc) {
   288			return -EIO;
   289		}
   290		if (fdap->fd_magic == MK32(fcbp->f_erase_value)) {
   291			return 0;
   292		}
   293		if (fdap->fd_magic != fcb_flash_magic(fcbp)) {
